import boto3

sqs = boto3.client('sqs')

def send_pii_data(queue_url, user_data):
    message = {
        'Email': user_data['email'],
        'Phone': user_data['phone_number'],
        'Address': user_data['address'],
    }

    sqs.send_message(
        QueueUrl=queue_url,
        MessageBody=str(message)
    )